 */

/**
 * Перевіряє роль користувача і перенаправляє відповідно до ролі
 * @param {string} userId - ID користувача для перевірки
 * @param {Function} navigate - Функція для навігації (з useNavigate)
 * @param {string} adminRedirectPath - Шлях для перенаправлення адміністраторів
 * @param {string} userRedirectPath - Шлях для перенаправлення звичайних користувачів
 * @returns {Promise<string|null>} - Роль користувача або null в разі помилки
 */
export const checkUserRoleAndRedirect = async (userId, navigate, adminRedirectPath = '/admin-dashboard', userRedirectPath = null) => {
  try {
    const response = await fetch(`http://localhost:5000/api/user-role/${userId}`);
