      console.error('Failed to verify user role');
      return null;
    }
    const data = await response.json();
    const role = data.role;

    // Перенаправляємо користувача відповідно до ролі
    if (role === 'admin' && navigate && adminRedirectPath) {
      navigate(adminRedirectPath);
    } else if (role === 'user' && navigate && userRedirectPath) {
      navigate(userRedirectPath);
    }
    return role;
  } catch (err) {
    console.error('Error checking user role:', err);
    return null;
  }
};

