/**
 * Утилітарні функції для авторизації та перевірки ролей користувачів
 */

/**
 * Перевіряє роль користувача і перенаправляє відповідно до ролі
 * @param {string} userId - ID користувача для перевірки
 * @param {Function} navigate - Функція для навігації (з useNavigate)
 * @param {string} adminRedirectPath - Шлях для перенаправлення адміністраторів
 * @param {string} userRedirectPath - Шлях для перенаправлення звичайних користувачів
 * @returns {Promise<string|null>} - Роль користувача або null в разі помилки
 */
export const checkUserRoleAndRedirect = async (userId, navigate, adminRedirectPath = '/admin-dashboard', userRedirectPath = null) => {
  try {
    const response = await fetch(`http://localhost:5000/api/user-role/${userId}`);
    if (!response.ok) {
      console.error('Failed to verify user role');
      return null;
    }
    
    const data = await response.json();
    const role = data.role;
    
    // Перенаправляємо користувача відповідно до ролі
    if (role === 'admin' && navigate && adminRedirectPath) {
      navigate(adminRedirectPath);
    } else if (role === 'user' && navigate && userRedirectPath) {
      navigate(userRedirectPath);
    }
    
    return role;
  } catch (err) {
    console.error('Error checking user role:', err);
    return null;
  }
};

/**
 * Перевіряє чи є поточний користувач адміністратором
 * @param {string} userId - ID користувача для перевірки
 * @returns {Promise<boolean>} - true якщо користувач є адміністратором
 */
export const isAdmin = async (userId) => {
  try {
    const response = await fetch(`http://localhost:5000/api/user-role/${userId}`);
    if (!response.ok) {
      return false;
    }
    
    const data = await response.json();
    return data.role === 'admin';
  } catch (err) {
    console.error('Error checking if user is admin:', err);
    return false;
  }
};

/**
 * Перевіряє авторизацію користувача і перенаправляє на домашню сторінку якщо не авторизований
 * @param {string|null} userId - ID користувача або null
 * @param {Function} navigate - Функція для навігації (з useNavigate)
 * @returns {boolean} - true якщо користувач авторизований
 */
export const checkAuth = (userId, navigate) => {
  if (!userId) {
    navigate('/');
    return false;
  }
  return true;
};
